UPDATE public.questions SET
  stimulus_text = 'Historians examining trade route 2 note that camel caravans carried not only goods but also astronomical tables, spreading navigation techniques across deserts long before printed maps existed. Merchants who survived the crossing depended on star charts copied onto leather scrolls, and those copies often accumulated marginal notes from later travelers. A ledger recovered near route 2 lists dates, caravan leaders, and the scientific texts exchanged at each oasis, suggesting that commerce and scholarship moved together. When one city tightened tariffs, caravans rerouted through secondary wells, and the astronomical knowledge rerouted with them. Modern scholars therefore treat desert trade networks as early information highways rather than simple supply chains. The passage emphasizes how practical navigation needs drove the circulation of technical knowledge among communities that rarely shared a written language.',
  question_text = 'Which choice best describes the overall structure of the passage?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"The passage is organized to compare two organizational responses to the same disruptive problem.","is_correct":true,"explanation":"The passage develops an explanatory arc matching to compare two organizational responses to the same disruptive problem, introducing context and then supporting evidence."},{"id":"B","text":"The passage lists unrelated facts with no thematic connection between paragraphs.","is_correct":false,"explanation":"The passage connects ideas across paragraphs; it is not a random list of disconnected facts."},{"id":"C","text":"The passage primarily argues that scientific research should be abandoned as unreliable.","is_correct":false,"explanation":"The passage presents research findings rather than rejecting scientific inquiry."},{"id":"D","text":"The passage provides a chronological biography of one individual from childhood to retirement.","is_correct":false,"explanation":"No single biography structures the passage; multiple actors and studies appear instead."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The passage is organized to compare two organizational responses to the same disruptive problem, moving from context to evidence to implication. Choice A names that rhetorical structure accurately. The distractors misread the passage as unstructured, anti-science, or biographical when it is explanatory and evidence-driven throughout.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"original":true,"generator":"scholaris_bulk_v1","explanation_v2":true,"english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.879Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
